    57			},
    58			setVersion: func(_ context.Context, version uint, dirty bool) error {
    59				r.operations = append(r.operations, runnerOperation{
    60					Kind:    "setVersion",
    61					Version: version,
    62					Dirty:   dirty,
    63				})
    64				if r.setVersionErr == nil {
    65					return nil
    66				}
    67				return r.setVersionErr[versionDirtyKey(version, dirty)]
    68			},
    69			updateDatabaseDDL: func(_ context.Context, statements []string) error {
    70				r.operations = append(r.operations, runnerOperation{
    71					Kind:       "ddl",
    72					Statements: append([]string(nil), statements...),
    73				})
    74				return r.ddlErr
    75			},
    76			applyDML: func(_ context.Context, statements []string) error {
    77				r.operations = append(r.operations, runnerOperation{
    78					Kind:       "dml",
    79					Statements: append([]string(nil), statements...),
    80				})
    81				return r.dmlErr
    82			},
    83			applyPartitionedDML: func(_ context.Context, statement string) (int64, error) {
    84				r.operations = append(r.operations, runnerOperation{
    85					Kind:      "partitionedDML",
    86					Statement: statement,
    87				})
    88				if r.partitionErr == nil {
    89					return 1, nil
    90				}
    91				return 0, r.partitionErr[statement]
    92			},
    93		}
    94	}
    95	
    96	func versionDirtyKey(version uint, dirty bool) string {
    97		return fmt.Sprintf("%d/%t", version, dirty)
    98	}
